import 'package:geolocator/geolocator.dart'; import 'package:injectable/injectable.dart'; @injectable class LocationPermissionService { Future<bool> request() async { var perm = await Geolocator.checkPermission(); if (perm == LocationPermission.denied) perm = await Geolocator.requestPermission(); return perm != LocationPermission.denied && perm != LocationPermission.deniedForever; } Future<bool> isGranted() async { final p = await Geolocator.checkPermission(); return p == LocationPermission.always || p == LocationPermission.whileInUse; } }